import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useWallet } from '../contexts/WalletContext';
import { getContract, getContractReadOnly } from '../utils/contract';
import {
  MessageSquare,
  Users,
  Crown,
  Plus,
  X,
  Loader,
  AlertCircle,
  Lock,
  Globe
} from 'lucide-react';

const Dashboard = () => {
  const { walletAddress, ownedNFTs } = useWallet();
  const [rooms, setRooms] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showCreateRoom, setShowCreateRoom] = useState(false);
  const [isCreating, setIsCreating] = useState(false);
  const [error, setError] = useState(null);
  const [roomForm, setRoomForm] = useState({
    name: '',
    isPrivate: false
  });

  /**
   * Fetch all rooms from blockchain
   */
  const fetchRooms = async () => {
    setLoading(true);
    setError(null);

    try {
      console.log('📥 Fetching all rooms from blockchain...');

      const contract = await getContractReadOnly();
      const allRooms = await contract.getAllRooms();
      
      console.log('📊 Raw rooms from blockchain:', allRooms.length);

      const roomsData = allRooms
        .filter(room => room.exists)
        .map(room => ({
          id: Number(room.id),
          name: room.name,
          creator: room.creator,
          isPrivate: room.isPrivate,
          createdAt: Number(room.createdAt),
          exists: room.exists
        }));

      setRooms(roomsData);
      console.log('✅ Displaying rooms:', roomsData.length);
      console.log('📋 Room IDs:', roomsData.map(r => r.id));
    } catch (err) {
      console.error('❌ Failed to fetch rooms:', err);
      setError(err.message || 'Failed to load rooms');
    } finally {
      setLoading(false);
    }
  };

  /**
   * Create room on blockchain
   */
  const handleCreateRoom = async (e) => {
    e.preventDefault();
    
    if (!roomForm.name.trim()) {
      setError('Please enter a room name');
      return;
    }

    setIsCreating(true);
    setError(null);

    try {
      console.log('🚀 Creating room on blockchain:', roomForm.name);

      // Get contract with signer
      const contract = await getContract();
      
      // Create room transaction
      const tx = await contract.createRoom(roomForm.name.trim(), roomForm.isPrivate);
      
      console.log('📝 Transaction sent:', tx.hash);
      
      // Wait for confirmation
      const receipt = await tx.wait();
      
      console.log('✅ Room created! Receipt:', receipt);

      // Extract room ID from event
      let roomId = null;
      if (receipt.logs && receipt.logs.length > 0) {
        try {
          const roomCreatedEvent = receipt.logs.find(log => {
            try {
              const parsed = contract.interface.parseLog(log);
              return parsed && parsed.name === 'RoomCreated';
            } catch {
              return false;
            }
          });

          if (roomCreatedEvent) {
            const parsed = contract.interface.parseLog(roomCreatedEvent);
            roomId = parsed.args.roomId?.toString();
          }
        } catch (err) {
          console.warn('Could not parse room ID:', err);
        }
      }

      alert(`✅ Room created successfully! Room ID: ${roomId}`);
      
      // Reset form and close modal
      setRoomForm({ name: '', isPrivate: false });
      setShowCreateRoom(false);
      
      // Refresh rooms list
      await fetchRooms();
      
    } catch (err) {
      console.error('❌ Failed to create room:', err);
      
      if (err.code === 'ACTION_REJECTED' || err.code === 4001) {
        setError('Transaction rejected by user');
      } else if (err.message?.includes('insufficient funds')) {
        setError('Insufficient funds to pay for gas');
      } else {
        setError(err.message || 'Failed to create room');
      }
    } finally {
      setIsCreating(false);
    }
  };

  /**
   * Format address
   */
  const formatAddress = (address) => {
    if (!address) return '';
    return `${address.slice(0, 6)}...${address.slice(-4)}`;
  };

  /**
   * Format date
   */
  const formatDate = (timestamp) => {
    try {
      const date = new Date(Number(timestamp) * 1000);
      return date.toLocaleDateString('en-US', {
        month: 'short',
        day: 'numeric',
        year: 'numeric'
      });
    } catch {
      return 'Unknown';
    }
  };

  /**
   * Fetch rooms on mount
   */
  useEffect(() => {
    fetchRooms();
  }, []);

  const createdRooms = rooms.filter(room => 
    room.creator.toLowerCase() === walletAddress?.toLowerCase()
  );

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Dashboard</h1>
          <p className="text-gray-600">Welcome back, {formatAddress(walletAddress)}</p>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="card">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 bg-primary-100 rounded-lg flex items-center justify-center">
              <MessageSquare className="w-5 h-5 text-primary-600" />
            </div>
            <div>
              <p className="text-sm text-gray-600">Total Rooms</p>
              <p className="text-2xl font-bold text-gray-900">{rooms.length}</p>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 bg-blue-100 rounded-lg flex items-center justify-center">
              <Plus className="w-5 h-5 text-blue-600" />
            </div>
            <div>
              <p className="text-sm text-gray-600">Rooms Created</p>
              <p className="text-2xl font-bold text-gray-900">{createdRooms.length}</p>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 bg-green-100 rounded-lg flex items-center justify-center">
              <Crown className="w-5 h-5 text-green-600" />
            </div>
            <div>
              <p className="text-sm text-gray-600">Owned NFTs</p>
              <p className="text-2xl font-bold text-gray-900">{ownedNFTs.length}</p>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 bg-purple-100 rounded-lg flex items-center justify-center">
              <Users className="w-5 h-5 text-purple-600" />
            </div>
            <div>
              <p className="text-sm text-gray-600">Network</p>
              <p className="text-sm font-bold text-gray-900">Sepolia</p>
            </div>
          </div>
        </div>
      </div>

      {/* Rooms Section */}
      <div className="card">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-lg font-semibold text-gray-900">Chat Rooms</h2>
          <button
            onClick={() => setShowCreateRoom(true)}
            className="btn-primary flex items-center space-x-2"
          >
            <Plus className="w-4 h-4" />
            <span>Create Room</span>
          </button>
        </div>

        {loading ? (
          <div className="flex flex-col items-center justify-center py-12">
            <Loader className="w-8 h-8 text-primary-600 animate-spin mb-4" />
            <p className="text-gray-600">Loading rooms from blockchain...</p>
          </div>
        ) : error ? (
          <div className="bg-red-50 border border-red-200 rounded-lg p-4">
            <div className="flex items-start space-x-3">
              <AlertCircle className="w-5 h-5 text-red-600 mt-0.5" />
              <div className="flex-1">
                <h3 className="text-red-900 font-medium mb-1">Failed to Load Rooms</h3>
                <p className="text-red-700 text-sm mb-3">{error}</p>
                <button
                  onClick={fetchRooms}
                  className="text-sm bg-red-600 hover:bg-red-700 text-white px-4 py-2 rounded-lg transition-colors"
                >
                  Try Again
                </button>
              </div>
            </div>
          </div>
        ) : rooms.length === 0 ? (
          <div className="text-center py-12">
            <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <MessageSquare className="w-8 h-8 text-gray-400" />
            </div>
            <h3 className="text-lg font-medium text-gray-900 mb-2">No Rooms Yet</h3>
            <p className="text-gray-600 mb-4">Be the first to create a chat room!</p>
          </div>
        ) : (
          <div className="space-y-4">
            {rooms.map((room) => (
              <div
                key={room.id}
                className="p-4 rounded-lg border-2 border-gray-200 hover:border-primary-300 transition-all"
              >
                <div className="flex items-center justify-between">
                  <div className="flex-1">
                    <div className="flex items-center space-x-3 mb-2">
                      <h3 className="font-semibold text-gray-900">{room.name}</h3>
                      {room.creator.toLowerCase() === walletAddress?.toLowerCase() && (
                        <span className="text-xs bg-blue-100 text-blue-700 px-2 py-1 rounded-full">
                          Creator
                        </span>
                      )}
                      {room.isPrivate ? (
                        <span className="text-xs bg-orange-100 text-orange-700 px-2 py-1 rounded-full flex items-center space-x-1">
                          <Lock className="w-3 h-3" />
                          <span>Private</span>
                        </span>
                      ) : (
                        <span className="text-xs bg-green-100 text-green-700 px-2 py-1 rounded-full flex items-center space-x-1">
                          <Globe className="w-3 h-3" />
                          <span>Public</span>
                        </span>
                      )}
                    </div>
                    <div className="flex items-center space-x-4 text-sm text-gray-500">
                      <span>Creator: {formatAddress(room.creator)}</span>
                      <span>•</span>
                      <span>Created: {formatDate(room.createdAt)}</span>
                      <span>•</span>
                      <span>Room ID: #{room.id}</span>
                    </div>
                  </div>

                  <div className="ml-4">
                    <Link
                      to={`/room/${room.id}`}
                      className="btn-primary"
                    >
                      Enter Room
                    </Link>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Create Room Modal */}
      {showCreateRoom && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg p-6 w-full max-w-md">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-semibold text-gray-900">Create New Room</h3>
              <button
                onClick={() => setShowCreateRoom(false)}
                className="p-1 text-gray-400 hover:text-gray-600"
              >
                <X className="w-5 h-5" />
              </button>
            </div>

            {error && (
              <div className="bg-red-50 border border-red-200 rounded-lg p-3 mb-4">
                <p className="text-red-700 text-sm">{error}</p>
              </div>
            )}

            <form onSubmit={handleCreateRoom} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Room Name
                </label>
                <input
                  type="text"
                  value={roomForm.name}
                  onChange={(e) => setRoomForm({ ...roomForm, name: e.target.value })}
                  placeholder="Enter room name"
                  className="input-field"
                  disabled={isCreating}
                  maxLength={50}
                  required
                />
              </div>

              <div>
                <label className="flex items-center space-x-3 cursor-pointer">
                  <input
                    type="checkbox"
                    checked={roomForm.isPrivate}
                    onChange={(e) => setRoomForm({ ...roomForm, isPrivate: e.target.checked })}
                    disabled={isCreating}
                    className="w-4 h-4 text-primary-600 border-gray-300 rounded focus:ring-primary-500"
                  />
                  <div>
                    <span className="text-sm font-medium text-gray-700">Private Room</span>
                    <p className="text-xs text-gray-500">Only invited members can join</p>
                  </div>
                </label>
              </div>

              <div className="bg-blue-50 border border-blue-200 rounded-lg p-3">
                <p className="text-blue-700 text-sm">
                  💡 Creating a room requires a blockchain transaction. MetaMask will ask for approval.
                </p>
              </div>

              <div className="flex space-x-3 pt-4">
                <button
                  type="button"
                  onClick={() => setShowCreateRoom(false)}
                  className="flex-1 btn-secondary"
                  disabled={isCreating}
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="flex-1 btn-primary flex items-center justify-center space-x-2"
                  disabled={isCreating}
                >
                  {isCreating ? (
                    <>
                      <Loader className="w-4 h-4 animate-spin" />
                      <span>Creating...</span>
                    </>
                  ) : (
                    <>
                      <Plus className="w-4 h-4" />
                      <span>Create Room</span>
                    </>
                  )}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;
